// RAG keyword search + detección de saludo breve
// v2026-04-17 — Gemini prompt + saludo separado + contexto RAG limpio

const httpResp = $input.first().json;
const chatInput = $('Preparar input').first().json.chatInput || '';

// ── Normalización ────────────────────────────────────────────────
const normalize = s => (s || '')
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9 ]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const inputNorm = normalize(chatInput);

// ── Período del día para saludo ──────────────────────────────────
function getPeriod() {
  try {
    const parts = new Intl.DateTimeFormat('es-AR', {
      hour: '2-digit',
      hour12: false,
      timeZone: 'America/Argentina/Buenos_Aires'
    }).formatToParts(new Date());
    const hour = Number(parts.find(p => p.type === 'hour')?.value ?? 12);
    if (hour >= 6 && hour < 12) return 'mañana';
    if (hour >= 12 && hour < 20) return 'tarde';
    return 'noche';
  } catch (e) {
    return 'tarde';
  }
}

const period = getPeriod();

// ── Detectar saludo puro → sin RAG ───────────────────────────────
// Importante: "hola necesito el logo" NO se considera saludo puro.
const SALUDOS_PUROS = new Set([
  '',
  'hola',
  'buenas',
  'buen dia',
  'buenos dias',
  'buenas tardes',
  'buenas noches',
  'como estas',
  'como va',
  'que tal',
  'ey',
  'hey',
  'que onda',
  'todo bien',
  'como andas',
  'que haces',
  'que contas',
  'como te va'
]);

const esGreeting = SALUDOS_PUROS.has(inputNorm);

if (esGreeting) {
  return [{
    json: {
      chatInput,
      contexto: '',
      chunks_encontrados: 0,
      es_greeting: true,
      es_casual: true,
      period
    }
  }];
}

// ── Obtener rawText con múltiples fallbacks ──────────────────────
let rawText = '';
try {
  rawText = httpResp.data || httpResp.body || httpResp.response || httpResp.text || '';
  if (typeof rawText !== 'string') rawText = JSON.stringify(rawText);
} catch(e) {
  return [{ json: { chatInput, contexto: '', chunks_encontrados: 0, es_greeting: false, es_casual: false, period, error: 'No se pudo leer el JSONL: ' + e.message } }];
}

if (!rawText.trim()) {
  return [{ json: { chatInput, contexto: '', chunks_encontrados: 0, es_greeting: false, es_casual: false, period, error: 'JSONL vacío o no accesible' } }];
}

// ── Parsear JSONL ────────────────────────────────────────────────
const chunks = [];
for (const line of rawText.split('\n')) {
  const l = line.trim();
  if (!l) continue;
  try { chunks.push(JSON.parse(l)); } catch { /* línea malformada, skip */ }
}

if (chunks.length === 0) {
  return [{ json: { chatInput, contexto: '', chunks_encontrados: 0, es_greeting: false, es_casual: false, period, error: 'No se pudieron parsear chunks' } }];
}

// ── Tokenizar query ──────────────────────────────────────────────
const STOPWORDS = new Set([
  'que','para','como','con','los','las','una','uno','del','por','son','hay',
  'esto','esta','este','ese','esa','pero','todo','todos','todas','cuando',
  'tiene','tengo','puedo','poder','quiero','necesito','busco','donde',
  'cuales','cuantos','algun','alguna','tienen','cual','dame','dime',
  'esta','estan','existe','existen','podria','pasame','mandame','dar','ver'
]);

const tokens = inputNorm
  .split(/\s+/)
  .filter(w => w.length >= 2 && !STOPWORDS.has(w));

if (tokens.length === 0) {
  return [{ json: { chatInput, contexto: '', chunks_encontrados: 0, es_greeting: false, es_casual: false, period } }];
}

// ── Scoring ──────────────────────────────────────────────────────
const scored = chunks.map(chunk => {
  const textoNorm = normalize(chunk.texto || '');
  const meta = chunk.metadata || {};
  const extraNorm = normalize([
    meta.palabras_clave,
    meta.nombre_recurso,
    meta.area_principal,
    meta.subarea_1,
    meta.subarea_2,
    meta.pagina,
    meta.seccion,
    meta.marca,
    meta.formato,
    meta.tipo_archivo,
    meta.url,
    meta.ruta
  ].filter(Boolean).join(' '));

  let score = 0;
  for (const token of tokens) {
    const safeToken = token.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const wordRe = new RegExp('\\b' + safeToken + '\\b', 'g');

    const m1 = textoNorm.match(wordRe);
    if (m1) score += m1.length * 2;
    else if (textoNorm.includes(token)) score += 1;

    const m2 = extraNorm.match(wordRe);
    if (m2) score += m2.length * 4;
    else if (extraNorm.includes(token)) score += 2;
  }

  // Bonus por recursos concretos y páginas útiles
  if (chunk.tipo_chunk === 'recurso') score += 3;
  if (chunk.tipo_chunk === 'pagina') score += 1;
  if (chunk.tipo_chunk === 'asistente') score += 1;

  return { chunk, score };
});

// ── Top K ────────────────────────────────────────────────────────
const TOP_K = 12;
const MAX_CHARS = 6500;

const topChunks = scored
  .filter(s => s.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, TOP_K)
  .map(s => s.chunk);

let contexto = '';
if (topChunks.length > 0) {
  const partes = [];
  let total = 0;
  for (const chunk of topChunks) {
    const parte = (chunk.texto || '').trim();
    if (!parte || total + parte.length > MAX_CHARS) break;
    partes.push(parte);
    total += parte.length;
  }
  contexto = partes.join('\n---\n');
}

return [{
  json: {
    chatInput,
    contexto,
    chunks_encontrados: topChunks.length,
    es_greeting: false,
    es_casual: false,
    period
  }
}];

